import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"74. Additional Payment Of Wages Provisions","description":"","frontmatter":{"title":"74. Additional Payment Of Wages Provisions","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","wages"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/wages/74-additional-payment-of-wages-provisions.md","filePath":"ebas/mental-health/rpn-pen-mho/wages/74-additional-payment-of-wages-provisions.md"}'),s={name:"ebas/mental-health/rpn-pen-mho/wages/74-additional-payment-of-wages-provisions.md"};function r(i,e,p,l,m,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_74-additional-payment-of-wages-provisions" tabindex="-1">74. Additional Payment Of Wages Provisions <a class="header-anchor" href="#_74-additional-payment-of-wages-provisions" aria-label="Permalink to &quot;74. Additional Payment Of Wages Provisions&quot;">​</a></h1><p>Note: To be read in conjunction with common provisions located at <a href="/eba/ebas/mental-health/common-terms/wages/29-payment-of-wages-allowances-employee-records-and.html">clause 29</a>.</p><p><strong>74.1</strong> Delays in processing pay</p><p><strong>(a)</strong> Subject to clauses 74.1(b) and 74.2, if an Employee is kept waiting for longer than the close of business on the business day following notification by the Employee to Payroll of an underpayment or non-payment under <a href="/eba/ebas/mental-health/common-terms/wages/29-payment-of-wages-allowances-employee-records-and.html">clauses 29.3</a> – 29.5, the Employee will be paid overtime rates for the duration of the period until such moneys owing are paid with a minimum payment of two hours and a maximum payment of seven hours and 36 minutes per day.</p><p><strong>(b)</strong> Clause 74.1 operates subject to:</p><p><strong>(i)</strong> the underpayment is 5% or more of the remuneration owed under <a href="/eba/ebas/mental-health/common-terms/wages/29-payment-of-wages-allowances-employee-records-and.html">clauses 29.3</a> – 29.4 or 29.5.</p><p><strong>(ii)</strong> except in cases of hardship, amounts less than 5% will be processed in the Employee’s next pay period.</p><p><strong>(c)</strong> where the Employee notifies the Employer of hardship in respect of an amount owing of less than 5%, the Employer will make its best endeavours to make the payment owing as soon as possible.</p><p><strong>(d)</strong> the Employer will notify the Employee of the adjustment being processed and provide the date of payment and any payment identification details</p><p><strong>(e)</strong> the Employer has fulfilled their obligations under clause 74.1 if payment has been processed by close of business on the next business day following notification by the Employee of an underpayment as described in clause 74.1(b)(i).</p><p><strong>(f)</strong> it is both parties’ obligation to complete and forward the timesheet for processing in accordance with the internal processes.</p><p><strong>(g)</strong> Where an underpayment or non-payment arises as a result of Employee error the penalty under clause 74.1 does not apply. However, upon notification, the Employer will make its best endeavours to make the payment owing as soon as possible.</p><p><strong>74.2</strong> Clause 74.1 will not come into effect if any unforeseen event or circumstance outside the control of the Employer frustrates the Employer&#39;s ability to meet the requirements of this clause.</p><p><strong>74.3</strong> Overpayments</p><p><strong>(a)</strong> In all cases where an overpayment of wages/entitlements has occurred, the Employer shall advise the Employee concerned and provide documentary evidence of the circumstances surrounding the claimed overpayment and the amount involved as soon as possible.</p><p><strong>(b)</strong> Once the Employee has received written details of the overpayment, the Employer and the Employee will meet to discuss the claimed overpayment with the aim of reaching an agreement about the alleged overpayment.</p><p><strong>(c)</strong> Where requested by the Employee, the Employer shall provide a full audit of the Employee’s payroll record.</p><p><strong>(d)</strong> Once agreement has been reached that an overpayment has occurred, the Employer and the Employee will agree in writing upon a scheme of repayment having regard to the Employee’s personal circumstances.</p><p><strong>(e)</strong> The Employee has the option to repay the overpayment in cash, through a deduction from wages or through another mutually agreed process.</p><p><strong>(f)</strong> The Employer will not make deductions from wages without written agreement from the Employee in relation to the quantum and timing of the deductions.</p><p><strong>(g)</strong> Where an Employee&#39;s remaining period of service does not permit the full recovery of any overpayment to be achieved in accordance with the agreed repayment arrangements, the Employer shall have the right to deduct any balance of such overpayment from monies owing to the Employee on the Employee&#39;s date of termination, resignation or retirement, as the case may be.</p><p><strong>(h)</strong> Where the circumstances make it appropriate, the Employer may exercise discretion not to pursue recovery of overpayments.</p><p><strong>(i)</strong> Where agreement cannot be reached on any of the matters contained in this clause, the Employee may invoke the Dispute Settling Procedures of this Agreement and no repayment will be commenced until the matter is resolved.</p>',23)])])}const y=t(s,[["render",r]]);export{c as __pageData,y as default};
